import React from 'react';
import styled from 'styled-components';


const Container = styled.div`
    width: 100%;
    min-height: 100vh;
`
const Nav = styled.div`
    width: 100%;
    height: 50px;
    display: flex;
    align-items: center;
    justify-content: space-evenly;
    background-color: black;
    color: white;
    position: fixed;
    top: 0;
    z-index: 90;
`

const NavItem = styled.a`
    color: white;
    text-decoration: none;
    margin-right: 30px;
    font-size: 18px;
    &:active{
        color: darkcyan;
        text-decoration: underline;
    }
    &:hover{
        color: darkcyan;
    }
`
const CartIcon = styled.div`
    width: 20px;
    height: 20px;
    border-radius: 50%;
    font-weight: 600;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: white;
    color: black;
    cursor: pointer;
`
const Holder = styled.div`
    width: 100vw;
    margin-top: 60px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    @media screen and (max-width:970px) {
        flex-direction: column;
        justify-content: center;
    }
`

const ItemsHolder = styled.div`
    width: 70%;
    margin: 10px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    border-right:1px solid rgb(216, 216, 216);
    @media screen and (max-width:970px) {
        width: 100%;
    }

`

const Item = styled.div`
    width: 90%;
    margin: 20px;
    padding: 30px;
    display: flex;
    align-items: center;
    justify-content: space-evenly;
    position: relative;
    border-radius: 10px;
    box-shadow: 2px 2px 2px 4px rgba(0, 0, 0, 0.3);

    @media screen and (max-width:580px) {
        flex-direction: column;
        padding: 5px;
        *{
            margin: 5px;
            padding: 5px;
        }
    }

`

const ItemImage = styled.img`
    width: 200px;
    height: auto;
    margin: 20px;
    object-fit: fill;
    object-position: center;
    border-radius: 5px;
`

const ItemDesc = styled.div`
    margin: 20px;
`

const Button = styled.button`
    width: 190px;
    height: 38px;
    position: absolute;
    bottom: 5px;
    right: 10px;
    border-radius: 5px;
    border: none;
    cursor: pointer;
    &:hover{
       background-color: #03c0c0;
       color: white;
    }
    @media screen and (max-width:580px) {
        position: relative;
    }
`
const Aside = styled.div`
    width: 30%;
    margin: 10px;
    padding: 20px;
    min-height: 30vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    font-weight: 500;

    @media screen and (max-width:970px) {
        width: 100%;
    }
`

const Store = () => {
    return (
        <Container>
            <Nav>
                <NavItem>ALL</NavItem>
                <NavItem>LAPTOPS</NavItem>
                <NavItem>PHONE</NavItem>
                <NavItem>WATCHES</NavItem>
                <NavItem>TABLETS</NavItem>
            </Nav>
            <Holder>
                <ItemsHolder>
                    <Item>
                        <ItemImage src='data:image/jpeg;base64,' />
                        <ItemDesc>
                            Lorem ipsum dolor sit, amet consectetur adipisicing elit. In molestias minus aliquam asperiores illum temporibus aperiam repudiandae vero eius, eligendi soluta odit ex accusantium illo dolor maiores consectetur? Assumenda, eligendi?
                        </ItemDesc>
                        <Button>ADD TO CART</Button>
                    </Item>

                    <Item>
                        <ItemImage src='data:image/jpeg;base64,' />
                        <ItemDesc>
                            Lorem ipsum dolor sit, amet consectetur adipisicing elit. In molestias minus aliquam asperiores illum temporibus aperiam repudiandae vero eius, eligendi soluta odit ex accusantium illo dolor maiores consectetur? Assumenda, eligendi?
                        </ItemDesc>
                        <Button className='inCart'>REMOVE FROM CART</Button>
                    </Item>
                </ItemsHolder>
                <Aside>
                    Lorem ipsum dolor sit amet consectetur adipisicing elit. Rem, expedita deserunt quis iste, totam provident rerum iusto adipisci ad, esse quam? Deleniti repellat adipisci eligendi error perspiciatis, alias sequi sed?
                </Aside>
            </Holder>
        </Container>
    );
}

export default Store;
